mapper.sql:
a.notice = false
and a.board_id = #{param.boardId}
and a.category_cd = #{param.categoryCd}
and a.title like '%' || #{param.title} || '%'
and a.posting = #{param.posting}
and a.created_dt >= to_timestamp(#{param.beginDay} || '000000', 'yyyymmddhh24miss')
and a.created_dt <= to_timestamp(#{param.endDay} || '000000', 'yyyymmddhh24miss')
and (
a.title like '%' || #{param.articleSrchWord} || '%'
a.article like '%' || #{param.articleSrchWord} || '%' or a.article_id in ( select article_id from cmmt_board_article_cn where header like '%' || #{param.articleSrchWord} || '%' or article_cn like '%' || #{param.articleSrchWord} || '%' )
a.title like '%' || #{param.articleSrchWord} || '%' or a.article like '%' || #{param.articleSrchWord} || '%' or a.article_id in ( select article_id from cmmt_board_article_cn where header like '%' || #{param.articleSrchWord} || '%' or article_cn like '%' || #{param.articleSrchWord} || '%' ) or b.login_id like '%' || #{param.articleSrchWord} || '%' or b.member_nm like '%' || #{param.articleSrchWord} || '%'
a.title like '%' || #{param.articleSrchWord} || '%' or a.article like '%' || #{param.articleSrchWord} || '%' or a.article_id in ( select article_id from cmmt_board_article_cn where header like '%' || #{param.articleSrchWord} || '%' or article_cn like '%' || #{param.articleSrchWord} || '%' )
)

mapper.select:
/** CmmtBoardArticleDao.selectList */ select
,#{totalItems} + 1 - (row_number() over (order by a.created_dt desc)) as rn from cmmt_board_article a left join cmmv_user b on a.creator_id = b.member_id where
offset #{beginRowNum} -1 limit #{itemsPerPage}

/** CmmtBoardArticleDao.selectList_notice */
select

	,row_number() over (order by created_dt desc) as rn
from
	cmmt_board_article
where
	notice = true

		and board_id = #{boardId}


		and category_cd = #{categoryCd}


		and posting = #{posting}

mapper.insert:
/** CmmtBoardArticleDao.insert */
insert into cmmt_board_article (
	 article_id
	,board_id
	,title
	,article
	,notice
	,attachment_group_id
	,image_group_id
	,category_cd
	,posting
	,web_editor
	,shared_url
	,pc_thumbnail_file_id
	,mobile_thumbnail_file_id
	,thumbnail_alt_cn
	,read_cnt
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
 ) values (
	 #{articleId}
	,#{boardId}
	,#{title}
	,#{article}
	,#{notice}
	,#{attachmentGroupId}
	,#{imageGroupId}
	,#{categoryCd}
	,#{posting}
	,#{webEditor}
	,#{sharedUrl}
	,#{pcThumbnailFileId}
	,#{mobileThumbnailFileId}
	,#{thumbnailAltCn}
	,#{readCnt}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
 )

mapper.update:
/** CmmtBoardArticleDao.update */
update cmmt_board_article set
	 board_id                 = #{boardId}
	,title                    = #{title}
	,article                  = #{article}
	,notice                   = #{notice}
	,attachment_group_id      = #{attachmentGroupId}
	,image_group_id           = #{imageGroupId}
	,category_cd              = #{categoryCd}
	,posting                  = #{posting}
	,web_editor               = #{webEditor}
	,shared_url               = #{sharedUrl}
	,pc_thumbnail_file_id     = #{pcThumbnailFileId}
	,mobile_thumbnail_file_id = #{mobileThumbnailFileId}
	,thumbnail_alt_cn         = #{thumbnailAltCn}
	,read_cnt                 = #{readCnt}
	,creator_id               = #{creatorId}
	,created_dt               = #{createdDt}
	,updater_id               = #{updaterId}
	,updated_dt               = #{updatedDt}
where
	article_id = #{articleId}

mapper.delete:
/** CmmtBoardArticleDao.delete */
delete from
	cmmt_board_article
where
	article_id = #{articleId}

mapper.update:
/** CmmtBoardArticleDao.incReadCnt */
update cmmt_board_article set
	read_cnt = read_cnt + 1
where
	article_id = #{articleId}

mapper.select:
/** CmmtBoardArticleDao.selectList_recent */
select

	,row_number() over(order by created_dt desc) as rn
from
	cmmt_board_article
where
	posting = true

		and board_id = #{boardId}


		and category_cd = #{categoryCd}


		and notice = false

limit #{cnt}

/** CmmtBoardArticleDao.selectPrevNext */ with tmp_article as (
select a.article_id ,a.board_id ,a.title ,a.notice ,a.created_dt from cmmt_board_article a where a.notice = true
and a.board_id = #{param.boardId}
and a.category_cd = #{param.categoryCd}
and a.posting = #{param.posting}
union all
select a.article_id ,a.board_id ,a.title ,a.notice ,a.created_dt from cmmt_board_article a left join cmmv_user b on a.creator_id = b.member_id where
) select y.board_id ,y.article_id ,y.title ,y.prev_article_id ,y.prev_title ,y.next_article_id ,y.next_title from ( select x.* ,lead(x.article_id) over w as prev_article_id ,lead(x.title) over w as prev_title ,lag(x.article_id) over w as next_article_id ,lag(x.title) over w as next_title from tmp_article x window w as (partition by x.board_id order by x.notice desc, x.created_dt desc) ) y where y.article_id = #{articleId}
